import { useState } from "react";
import "./EvaluateBatch.css";

const STEPS = ["Setup", "Upload", "Review", "Results"];

export default function EvaluateBatch() {
  const [currentStep, setCurrentStep] = useState(0);

  // Step 1 data
  const [subject, setSubject] = useState("");
  const [totalMarks, setTotalMarks] = useState("");
  const [modelAnswer, setModelAnswer] = useState("");

  // Step 2 data
  const [pdfFile, setPdfFile] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // Step 3 data
  const [extractedStudents, setExtractedStudents] = useState([]);

  // Step 4 data
  const [results, setResults] = useState([]);
  const [isEvaluating, setIsEvaluating] = useState(false);
  const [evaluationProgress, setEvaluationProgress] = useState(0);

  const goNext = () => setCurrentStep((s) => s + 1);
  const goBack = () => setCurrentStep((s) => s - 1);

  return (
    <div className="batch-container">
      <StepIndicator steps={STEPS} current={currentStep} />

      {currentStep === 0 && (
        <SetupStep
          subject={subject}
          setSubject={setSubject}
          totalMarks={totalMarks}
          setTotalMarks={setTotalMarks}
          modelAnswer={modelAnswer}
          setModelAnswer={setModelAnswer}
          onNext={goNext}
        />
      )}

      {currentStep === 1 && (
        <UploadStep
          pdfFile={pdfFile}
          setPdfFile={setPdfFile}
          isProcessing={isProcessing}
          setIsProcessing={setIsProcessing}
          setExtractedStudents={setExtractedStudents}
          subject={subject}
          totalMarks={totalMarks}
          onNext={goNext}
          onBack={goBack}
        />
      )}

      {currentStep === 2 && (
        <ReviewStep
          students={extractedStudents}
          setStudents={setExtractedStudents}
          isEvaluating={isEvaluating}
          progress={evaluationProgress}
          onEvaluate={() =>
            handleEvaluate({
              extractedStudents,
              modelAnswer,
              totalMarks,
              setIsEvaluating,
              setEvaluationProgress,
              setResults,
              goNext,
            })
          }
          onBack={goBack}
        />
      )}

      {currentStep === 3 && (
        <ResultsStep
          results={results}
          subject={subject}
          totalMarks={totalMarks}
        />
      )}
    </div>
  );
}

// ─── STEP 1: Setup ───────────────────────────────────────────
function SetupStep({
  subject,
  setSubject,
  totalMarks,
  setTotalMarks,
  modelAnswer,
  setModelAnswer,
  onNext,
}) {
  const isValid = subject.trim() && totalMarks;

  return (
    <div className="step-card">
      <h2>Step 1: Exam Setup</h2>
      <p className="step-desc">
        Subject aur total marks enter karo. Model answer optional hai.
      </p>

      <div className="form-group">
        <label>Subject Name *</label>
        <input
          type="text"
          value={subject}
          onChange={(e) => setSubject(e.target.value)}
          placeholder="e.g. Data Structures"
        />
      </div>

      <div className="form-group">
        <label>Total Marks *</label>
        <input
          type="number"
          value={totalMarks}
          onChange={(e) => setTotalMarks(e.target.value)}
          placeholder="e.g. 50"
          min="1"
        />
      </div>

      <div className="form-group">
        <label>Model Answer (Optional)</label>
        <textarea
          value={modelAnswer}
          onChange={(e) => setModelAnswer(e.target.value)}
          placeholder="Ideal answer paste karo — isse evaluation zyada accurate hogi"
          rows={5}
        />
      </div>

      <button className="btn-primary" onClick={onNext} disabled={!isValid}>
        Next: Upload PDF →
      </button>
    </div>
  );
}

// ─── STEP 2: Upload ───────────────────────────────────────────
function UploadStep({
  pdfFile,
  setPdfFile,
  isProcessing,
  setIsProcessing,
  setExtractedStudents,
  subject,
  totalMarks,
  onNext,
  onBack,
}) {
  const handleFileChange = (e) => {
    setPdfFile(e.target.files[0]);
  };

  const handleProcess = async () => {
    if (!pdfFile) return;
    setIsProcessing(true);

    try {
      const formData = new FormData();
      formData.append("file", pdfFile);
      formData.append("subject", subject);
      formData.append("total_marks", totalMarks);

      const res = await fetch("/api/evaluate/bulk/extract", {
        method: "POST",
        headers: {
          Authorization: `Bearer ${localStorage.getItem("token")}`,
        },
        body: formData,
      });

      const data = await res.json();

      if (data.success) {
        setExtractedStudents(
          data.students.map((s) => ({ ...s, edited: false }))
        );
        onNext();
      } else {
        alert("Error: " + data.message);
      }
    } catch (err) {
      alert("Server error: " + err.message);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="step-card">
      <h2>Step 2: Upload Class PDF</h2>
      <p className="step-desc">
        Poori class ka combined PDF upload karo. Har student ki sheet alag honi
        chahiye. System automatically name aur roll number extract karega.
      </p>

      <div
        className="upload-box"
        onClick={() => document.getElementById("bulk-pdf").click()}
      >
        {pdfFile ? (
          <div className="file-selected">
            <span>📄</span>
            <p>{pdfFile.name}</p>
            <small>{(pdfFile.size / 1024 / 1024).toFixed(2)} MB</small>
          </div>
        ) : (
          <div className="upload-placeholder">
            <span>📁</span>
            <p>Click to upload PDF</p>
            <small>Combined class answer sheets</small>
          </div>
        )}
        <input
          id="bulk-pdf"
          type="file"
          accept=".pdf"
          style={{ display: "none" }}
          onChange={handleFileChange}
        />
      </div>

      <div className="step-actions">
        <button className="btn-secondary" onClick={onBack}>
          ← Back
        </button>
        <button
          className="btn-primary"
          onClick={handleProcess}
          disabled={!pdfFile || isProcessing}
        >
          {isProcessing ? "Processing... ⏳" : "Extract Students →"}
        </button>
      </div>
    </div>
  );
}

// ─── STEP 3: Review Extracted Students ───────────────────────
function ReviewStep({
  students,
  setStudents,
  isEvaluating,
  progress,
  onEvaluate,
  onBack,
}) {
  const handleEdit = (index, field, value) => {
    const updated = [...students];
    updated[index] = { ...updated[index], [field]: value, edited: true };
    setStudents(updated);
  };

  return (
    <div className="step-card wide">
      <h2>Step 3: Review Extracted Students</h2>
      <p className="step-desc">
        System ne ye students detect kiye hain. Koi galti ho toh edit kar sakte
        ho.
      </p>

      <div className="students-table-wrapper">
        <table className="students-table">
          <thead>
            <tr>
              <th>#</th>
              <th>Name</th>
              <th>Roll No</th>
              <th>Pages</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            {students.map((s, i) => (
              <tr key={i} className={s.edited ? "edited-row" : ""}>
                <td>{i + 1}</td>
                <td>
                  <input
                    value={s.name}
                    onChange={(e) => handleEdit(i, "name", e.target.value)}
                    className="inline-edit"
                  />
                </td>
                <td>
                  <input
                    value={s.roll_no}
                    onChange={(e) => handleEdit(i, "roll_no", e.target.value)}
                    className="inline-edit"
                  />
                </td>
                <td className="pages-cell">{s.page_range || "Auto"}</td>
                <td>
                  <span className={`status-badge ${s.status}`}>
                    {s.status === "found" ? "✅ Registered" : "🆕 New"}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {isEvaluating && (
        <div className="progress-section">
          <p>Evaluating students... {progress}%</p>
          <div className="progress-bar">
            <div
              className="progress-fill"
              style={{ width: `${progress}%` }}
            />
          </div>
        </div>
      )}

      <div className="step-actions">
        <button
          className="btn-secondary"
          onClick={onBack}
          disabled={isEvaluating}
        >
          ← Back
        </button>
        <button
          className="btn-primary"
          onClick={onEvaluate}
          disabled={isEvaluating}
        >
          {isEvaluating ? `Evaluating... ${progress}%` : "🚀 Start Evaluation"}
        </button>
      </div>
    </div>
  );
}

// ─── STEP 4: Results ─────────────────────────────────────────
function ResultsStep({ results, subject, totalMarks }) {
  const average = results.length
    ? (
        results.reduce((sum, r) => sum + r.obtained_marks, 0) / results.length
      ).toFixed(1)
    : 0;

  return (
    <div className="step-card wide">
      <h2>✅ Evaluation Complete</h2>
      <p className="step-desc">Subject: <strong>{subject}</strong></p>

      <div className="results-summary">
        <div className="summary-card">
          <span>{results.length}</span>
          <label>Total Students</label>
        </div>
        <div className="summary-card">
          <span>{average}</span>
          <label>Class Average</label>
        </div>
        <div className="summary-card">
          <span>{totalMarks}</span>
          <label>Total Marks</label>
        </div>
      </div>

      <table className="students-table">
        <thead>
          <tr>
            <th>#</th>
            <th>Name</th>
            <th>Roll No</th>
            <th>Obtained</th>
            <th>Total</th>
            <th>%</th>
            <th>Remarks</th>
          </tr>
        </thead>
        <tbody>
          {results.map((r, i) => (
            <tr key={i}>
              <td>{i + 1}</td>
              <td>{r.name}</td>
              <td>{r.roll_no}</td>
              <td>
                <strong>{r.obtained_marks}</strong>
              </td>
              <td>{totalMarks}</td>
              <td>{((r.obtained_marks / totalMarks) * 100).toFixed(1)}%</td>
              <td className="remarks-cell">{r.remarks}</td>
            </tr>
          ))}
        </tbody>
      </table>

      <div className="step-actions">
        <button
          className="btn-secondary"
          onClick={() => window.location.reload()}
        >
          🔄 New Evaluation
        </button>
        <button className="btn-primary">📥 Export Results</button>
      </div>
    </div>
  );
}

// ─── STEP INDICATOR ───────────────────────────────────────────
function StepIndicator({ steps, current }) {
  return (
    <div className="step-indicator">
      {steps.map((step, i) => (
        <div
          key={i}
          className={`step-dot ${
            i === current ? "active" : i < current ? "done" : ""
          }`}
        >
          <div className="dot">{i < current ? "✓" : i + 1}</div>
          <span>{step}</span>
          {i < steps.length - 1 && <div className="step-line" />}
        </div>
      ))}
    </div>
  );
}

// ─── EVALUATE HANDLER ─────────────────────────────────────────
async function handleEvaluate({
  extractedStudents,
  modelAnswer,
  totalMarks,
  setIsEvaluating,
  setEvaluationProgress,
  setResults,
  goNext,
}) {
  setIsEvaluating(true);
  setEvaluationProgress(0);

  // Start fake progress before await
  const progressInterval = setInterval(() => {
    setEvaluationProgress((p) => Math.min(p + 10, 90));
  }, 800);

  try {
    const res = await fetch("/api/evaluate/bulk", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({
        students: extractedStudents,
        model_answer: modelAnswer,
        total_marks: totalMarks,
      }),
    });

    const data = await res.json();
    clearInterval(progressInterval);
    setEvaluationProgress(100);

    if (data.success) {
      setResults(data.results);
      setTimeout(goNext, 500);
    } else {
      alert("Evaluation failed: " + data.message);
    }
  } catch (err) {
    clearInterval(progressInterval);
    alert("Error: " + err.message);
  } finally {
    setIsEvaluating(false);
  }
}
